const record = $input.item.json;
const topic = record.fields?.Topic || '';
const brief = record.fields?.Brief || '';
const platform = Array.isArray(record.fields?.Platform) ? record.fields.Platform.join(', ') : (record.fields?.Platform || 'Instagram + LinkedIn');
const contentType = record.fields?.['Content Type'] || 'Carousel';
const relatedService = record.fields?.['Related Service'] || 'SEO';

// Extract key message from brief
const keyMsgMatch = brief.match(/KEY MESSAGE[:\s]+([^\n]+)/i);
const keyMessage = keyMsgMatch ? keyMsgMatch[1].trim() : topic;

const ctaMatch = brief.match(/CTA[:\s]+([^\n]+)/i);
const cta = ctaMatch ? ctaMatch[1].trim() : 'Get your free AI audit';

// Build a precise DALL-E prompt
const prompt = `Professional social media ${contentType} graphic for SecurityBlogs.com.au, an AI visibility and SEO agency for the Australian security industry.

TOPIC: ${topic}
PLATFORM: ${platform}
SERVICE: ${relatedService}
KEY MESSAGE: ${keyMessage}
CTA: ${cta}

DESIGN REQUIREMENTS:
- Dark navy background (#0a0f1e) with electric blue accents (#1e5fe0) and red highlights (#e23744)
- Bold, clean sans-serif typography. Large headline text dominating the top third.
- Professional security industry imagery (abstract tech, shields, data, AI networks)
- SecurityBlogs.com.au branding subtle in corner
- Modern, trustworthy, conversion-focused layout
- Clear visual hierarchy: headline → supporting point → CTA
- No stock-photo feel. Premium agency aesthetic.
- Aspect ratio: 1:1 (1080x1080) suitable for ${platform}
- No faces. No people. Abstract professional visuals only.`;

return [{ json: { recordId: record.id, topic, platform, contentType, prompt, cta } }];

const dalleResponse = $input.item.json;
const imageUrl = dalleResponse?.data?.[0]?.url || '';
const revisedPrompt = dalleResponse?.data?.[0]?.revised_prompt || '';
const prev = $('Build DALL-E Prompt').item.json;
if (!imageUrl) throw new Error('DALL-E returned no image URL');
return [{ json: { ...prev, imageUrl, revisedPrompt } }];
